import { useNavigate } from "react-router-dom";

function Home() {

    const navigate = useNavigate();

    return (

        <div style={{ padding: "30px" }}>

            <h1>Complaint Management System</h1>

            <br />

            <button
                onClick={() => navigate("/login")}
            >
                Login
            </button>

        </div>
    );
}

export default Home;
